'use client';
import { useToast } from '@/hooks/use-toast';
import { useDebounce } from 'use-debounce';
import { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import EditCategoryDialog from '@/components/dialog/EditCategoryDialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { useAuth } from '@/context/AuthContext';
import { HostCategory } from '@/types';
import SearchInput from '@/components/ui/SearchInput';
import { fetchCategories } from '@/api/hostCategories';
import Pagination from '@/components/ui/Pagination';
import { Loading } from '@/components/ui/Loading';
import NotFound from '@/components/ui/NotFound';
import CategorieCard from '@/components/ui/CategorieCard';
import { AddCategoryDialog } from '@/components/dialog/AddCategoryDialog';

const HostCategoriesPage = () => {
  const { toast } = useToast();
  const { token } = useAuth();
  const [selectedCategory, setSelectedCategory] = useState<HostCategory | null>(
    null
  );
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);

  const [categories, setCategories] = useState<HostCategory[]>([]);
  const [filtered, setFiltered] = useState<HostCategory[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [activeFilter, setActiveFilter] = useState<string>('all');

  const [currentPage, setCurrentPage] = useState(1);
  const [categoriesPerPage] = useState(6);
  const [loading, setLoading] = useState(false);

  // حساب الأحداث للصفحة الحالية
  const indexOfLastEvent = currentPage * categoriesPerPage;
  const indexOfFirstEvent = indexOfLastEvent - categoriesPerPage;
  const currentHostCategories = filtered.slice(
    indexOfFirstEvent,
    indexOfLastEvent
  );
  const totalPages = Math.ceil(filtered.length / categoriesPerPage);

  useEffect(() => {
    fetchCategories(
      setLoading,
      currentPage,
      categoriesPerPage,
      true,
      toast
    ).then((data) => setCategories(data));
  }, [currentPage]);

  useEffect(() => {
    let temp = [...categories];
    if (activeFilter !== 'all') {
      temp = temp.filter((c) => c.name === activeFilter);
    }
    if (debouncedQuery.trim()) {
      temp = temp.filter(
        (c) =>
          c.name.toLowerCase().includes(debouncedQuery.toLowerCase()) ||
          c.description.toLowerCase().includes(debouncedQuery.toLowerCase())
      );
    }
    setFiltered(temp);
  }, [debouncedQuery, activeFilter, categories]);

  const uniqueFilters = [
    'all',
    ...Array.from(new Set(categories?.map((c) => c?.name))),
  ];

  const handleDelete = async () => {
    if (!selectedCategory) return;
    try {
      const res = await fetch(
        `http://localhost:8080/host-categories/${selectedCategory._id}`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      toast({
        title: 'Category Deleted',
        description: `${selectedCategory.name} was deleted successfully.`,
        className: 'bg-green-600 text-white border-0',
      });
      setFiltered((prev) => prev.filter((c) => c._id !== selectedCategory._id));
    } catch (err: any) {
      toast({
        title: 'Error',
        description: err.message,
        variant: 'destructive',
      });
    } finally {
      setIsDeleteDialogOpen(false);
    }
  };
  const handleAdd = async (newCategory: {
    name: string;
    description: string;
  }) => {
    try {
      const response = await fetch(`http://localhost:8080/host-categories`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newCategory),
      });

      const data = await response.json();

      toast({
        title: 'successfully!',
        description: data.message || 'Category added successfully!',
        className: 'bg-green-600 text-white border-0',
      });

      setCategories((prev) => [...prev, data.categories]);
      // Optionally re-fetch categories or just append:
      setFiltered((prev) => [...prev, data.categories]);

      setIsAddDialogOpen(false);

      fetchCategories(
        setLoading,
        currentPage,
        categoriesPerPage,
        true,
        toast
      ).then((data) => setCategories(data));
    } catch (error: any) {
      toast({
        title: 'error',
        description: error.message || 'Something went wrong.',
        variant: 'destructive',
      });
    }
  };

  // تغيير الصفحة
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);
  if (loading) {
    return <Loading />;
  }
  return (
    <div className='p-6 space-y-6'>
      {/* Search & Filter */}
      <div className='flex flex-col md:flex-row justify-between items-center gap-4'>
        {/* Search Input */}
        <SearchInput
          name='Host Categories'
          searchQuery={searchQuery}
          setSearchQuery={setSearchQuery}
          setCurrentPage={() => setCurrentPage(1)}
        />
        <div className='flex justify-between items-center'>
          <div className='flex justify-end'>
            <Button
              className='mr-4 bg-purple-800'
              onClick={() => setIsAddDialogOpen(true)}
            >
              + Add Host Category
            </Button>
          </div>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant='outline'
                className='capitalize w-full md:w-40'
              >
                {activeFilter}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent>
              {uniqueFilters.map((filter) => (
                <DropdownMenuItem
                  key={filter}
                  onClick={() => setActiveFilter(filter)}
                  className='capitalize cursor-pointer'
                >
                  {filter}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>

      {currentHostCategories.length > 0 ? (
        <div className='grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6'>
          {currentHostCategories.map((categorie, index) => (
            <CategorieCard
              key={categorie._id}
              index={index}
              categorie={categorie}
              onEdit={() => {
                setSelectedCategory(categorie);
                setIsEditDialogOpen(true);
              }}
              onDelete={() => {
                setSelectedCategory(categorie);
                setIsDeleteDialogOpen(true);
              }}
            />
          ))}
        </div>
      ) : (
        <NotFound message='The Host Categories are not found' />
      )}

      {/* (Dialogs) */}
      <EditCategoryDialog
        open={isEditDialogOpen}
        onClose={() => setIsEditDialogOpen(false)}
        category={selectedCategory}
        token={token}
        onSuccess={(updatedCategory) => {
          setCategories((prev) =>
            prev.map((c) =>
              c?._id === updatedCategory?._id ? updatedCategory : c
            )
          );
          setIsEditDialogOpen(false);
        }}
        toast={toast}
      />
      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onClose={() => setIsDeleteDialogOpen(false)}
        title='Delete Host Category'
        description={`Are you sure you want to delete ${selectedCategory?.name}?`}
        onConfirm={handleDelete}
      />
      <AddCategoryDialog
        open={isAddDialogOpen}
        onClose={() => setIsAddDialogOpen(false)}
        onSubmit={handleAdd}
      />
      {/* Pagination Controls */}
      {filtered.length > 0 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          paginate={paginate}
        />
      )}
    </div>
  );
};
export default HostCategoriesPage;
